import type { DocumentPostingStatusResult } from '../services/kt/models';

export interface PollPostingStatusOptions {
  intervalMs?: number;
  maxAttempts?: number;
}

const TERMINAL = new Set(['Posted', 'Failed']);

/**
 * Poll GET posting-status until Posted, Failed, or timeout.
 */
export async function pollDocumentPostingStatus(
  getStatus: () => Promise<DocumentPostingStatusResult>,
  options?: PollPostingStatusOptions,
): Promise<DocumentPostingStatusResult> {
  const intervalMs = options?.intervalMs ?? 1000;
  const maxAttempts = options?.maxAttempts ?? 90;

  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    const status = await getStatus();
    if (TERMINAL.has(status.postingStatus)) {
      return status;
    }
    if (status.postingStatus === 'None') {
      return status;
    }
    await new Promise(resolve => setTimeout(resolve, intervalMs));
  }

  throw new Error('POSTING_POLL_TIMEOUT');
}
